service cloud.firestore {
  match /databases/{database}/documents {

    // Collection: users
    // - Sesiapa yang dah login boleh READ (perlu untuk lecturer list & role check)
    // - User hanya boleh EDIT profile dia sendiri
    match /users/{userId} {
      allow read: if request.auth != null;
      allow write: if request.auth != null && request.auth.uid == userId;
    }

    // Collection: chats
    // - Hanya participant (student/lecturer yang terlibat) boleh read/write chat tu
    match /chats/{chatId} {
      allow read, write: if request.auth != null &&
                          request.auth.uid in resource.data.participants;

      // Untuk create chat baru (document belum wujud lagi)
      allow create: if request.auth != null &&
                     request.auth.uid in request.resource.data.participants;

      // Sub-collection: messages
      match /messages/{messageId} {
        allow read: if request.auth != null &&
                     request.auth.uid in get(/databases/$(database)/documents/chats/$(chatId)).data.participants;

        allow create: if request.auth != null &&
                       request.auth.uid in get(/databases/$(database)/documents/chats/$(chatId)).data.participants &&
                       request.resource.data.senderId == request.auth.uid;

        // Elak sesiapa edit/delete mesej lepas dihantar
        allow update, delete: if false;
      }
    }
  }
}

